/// Raw FFI bindings auto-generated by bindgen from MumblePlugin.h.
/// Contains type definitions AND function declarations — we only use the types.
#[allow(non_upper_case_globals)]
#[allow(non_camel_case_types)]
#[allow(non_snake_case)]
#[allow(dead_code)]
mod ffi {
    include!(concat!(env!("OUT_DIR"), "/bindings.rs"));
}

use ffi::{
    mumble_channelid_t, mumble_connection_t, mumble_error_t, mumble_plugin_id_t,
    mumble_talking_state_t, mumble_mute_state_t, mumble_deaf_state_t,
    mumble_transmission_mode_t, mumble_settings_key_t,
    mumble_userid_t, mumble_version_t, Mumble_ErrorCode_MUMBLE_EC_OK,
    Mumble_TalkingState_MUMBLE_TS_PASSIVE, Mumble_TalkingState_MUMBLE_TS_TALKING,
    Mumble_TalkingState_MUMBLE_TS_TALKING_MUTED, Mumble_TalkingState_MUMBLE_TS_WHISPERING,
    Mumble_TalkingState_MUMBLE_TS_SHOUTING,
    Mumble_TransmissionMode_MUMBLE_TM_CONTINOUS,
    Mumble_TransmissionMode_MUMBLE_TM_VOICE_ACTIVATION,
    Mumble_TransmissionMode_MUMBLE_TM_PUSH_TO_TALK,
    Mumble_SettingsKey_MUMBLE_SK_AUDIO_INPUT_VOICE_HOLD,
    Mumble_SettingsKey_MUMBLE_SK_AUDIO_INPUT_VAD_SILENCE_THRESHOLD,
    Mumble_SettingsKey_MUMBLE_SK_AUDIO_INPUT_VAD_SPEECH_THRESHOLD,
    MumbleAPI_v_1_3_x, MumbleStringWrapper,
};

use bridge_types::{MumbleEvent, MumbleCommand, TalkingState, TransmissionMode, Channel, User};
use interprocess::local_socket::{prelude::*, GenericNamespaced, Stream};
use std::ffi::{c_void, CStr, CString};
use std::io::{BufRead, BufReader, BufWriter, Write};
use std::sync::{mpsc, Mutex};

const OK: mumble_error_t = Mumble_ErrorCode_MUMBLE_EC_OK as mumble_error_t;

static STATE: Mutex<Option<PluginState>> = Mutex::new(None);

struct PluginState {
    id: mumble_plugin_id_t,
    api: MumbleAPI_v_1_3_x,
    connection: Option<mumble_connection_t>,
    event_tx: Option<mpsc::Sender<MumbleEvent>>,
}

unsafe impl Send for PluginState {}

fn send_event(event: MumbleEvent) {
    let state = STATE.lock().unwrap();
    if let Some(ref s) = *state {
        if let Some(ref tx) = s.event_tx {
            let _ = tx.send(event);
        }
    }
}

fn mumble_log(msg: &str) {
    let state = STATE.lock().unwrap();
    if let Some(ref s) = *state {
        if let Ok(c_msg) = CString::new(msg) {
            unsafe { (s.api.log.unwrap())(s.id, c_msg.as_ptr()) };
        }
    }
}

fn static_string(s: &'static [u8]) -> MumbleStringWrapper {
    MumbleStringWrapper {
        data: s.as_ptr() as *const i8,
        size: s.len() - 1,
        needsReleasing: false,
    }
}

// ==================== MANDATORY PLUGIN FUNCTIONS ====================

#[no_mangle]
pub extern "C" fn mumble_registerAPIFunctions(api_struct: *mut c_void) {
    let api = unsafe { *(api_struct as *mut MumbleAPI_v_1_3_x) };
    let mut state = STATE.lock().unwrap();
    *state = Some(PluginState {
        id: 0,
        api,
        connection: None,
        event_tx: None,
    });
}

#[no_mangle]
pub extern "C" fn mumble_init(id: mumble_plugin_id_t) -> mumble_error_t {
    let mut state = STATE.lock().unwrap();
    let Some(ref mut s) = *state else {
        return OK;
    };
    s.id = id;

    if let Ok(msg) = CString::new("etch-bridge plugin loaded") {
        unsafe { (s.api.log.unwrap())(s.id, msg.as_ptr()) };
    }

    let sock_name = match std::env::var("ETCH_BRIDGE_SOCK") {
        Ok(name) => name,
        Err(_) => {
            // No socket configured — plugin runs in passive mode (log only).
            return OK;
        }
    };

    let (event_tx, event_rx) = mpsc::channel();
    s.event_tx = Some(event_tx);

    let api = s.api;
    let plugin_id = s.id;

    std::thread::spawn(move || {
        if let Err(e) = ipc_thread(sock_name, event_rx, api, plugin_id) {
            eprintln!("[etch-bridge] IPC thread error: {}", e);
        }
    });

    OK
}

#[no_mangle]
pub extern "C" fn mumble_shutdown() {
    let mut state = STATE.lock().unwrap();
    if let Some(ref mut s) = *state {
        // Drop the sender so the IPC writer loop exits.
        s.event_tx = None;
    }
}

