#[no_mangle]
pub extern "C" fn mumble_onUserTalkingStateChanged(
    _connection: mumble_connection_t,
    user_id: mumble_userid_t,
    talking_state: mumble_talking_state_t,
) {
    let state = STATE.lock().unwrap();
    let Some(ref s) = *state else { return };
    if s.connection.is_none() { return; }

    #[allow(non_upper_case_globals)]
    let bridge_state = match talking_state {
        Mumble_TalkingState_MUMBLE_TS_PASSIVE => TalkingState::Passive,
        Mumble_TalkingState_MUMBLE_TS_TALKING => TalkingState::Talking,
        Mumble_TalkingState_MUMBLE_TS_WHISPERING => TalkingState::Whispering,
        Mumble_TalkingState_MUMBLE_TS_SHOUTING => TalkingState::Shouting,
        Mumble_TalkingState_MUMBLE_TS_TALKING_MUTED => TalkingState::TalkingMuted,
        _ => return,
    };

    if let Some(ref tx) = s.event_tx {
        let _ = tx.send(MumbleEvent::UserTalking { session: user_id, state: bridge_state });
    }
}

