// ==================== IPC ====================

fn ipc_thread(
    sock_name: String,
    event_rx: mpsc::Receiver<MumbleEvent>,
    api: MumbleAPI_v_1_3_x,
    plugin_id: mumble_plugin_id_t,
) -> std::io::Result<()> {
    mumble_log(&format!("[etch-bridge] Connecting to {}", sock_name));

    let name = sock_name.to_ns_name::<GenericNamespaced>()?;
    let stream = Stream::connect(name)?;

    let (recv, send) = stream.split();

    // Reader thread — receives commands from etch-core
    std::thread::spawn(move || {
        let reader = BufReader::new(recv);
        for line in reader.lines() {
            let line = match line {
                Ok(l) => l,
                Err(_) => break,
            };
            if line.is_empty() { continue; }
            match serde_json::from_str::<MumbleCommand>(&line) {
                Ok(cmd) => execute_command(api, plugin_id, &cmd),
                Err(e) => eprintln!("[etch-bridge] Bad command: {}", e),
            }
        }
    });

    // Writer loop — sends events to etch-core
    let mut writer = BufWriter::new(send);
    for event in event_rx {
        if let Ok(json) = serde_json::to_string(&event) {
            let _ = writer.write_all(json.as_bytes());
            let _ = writer.write_all(b"\n");
            let _ = writer.flush();
        }
    }

    Ok(())
}

fn execute_command(api: MumbleAPI_v_1_3_x, plugin_id: mumble_plugin_id_t, cmd: &MumbleCommand) {
    // Read connection from STATE, then drop the lock before calling API.
    // API calls are RPC'd to Mumble's main thread — holding the lock would deadlock
    // if a callback fires and tries to lock STATE.
    let connection = {
        let state = STATE.lock().unwrap();
        state.as_ref().and_then(|s| s.connection)
    };
    let Some(connection) = connection else { return };

    unsafe {
        match cmd {
            MumbleCommand::SwitchChannel { channel_id } => {
                let mut local_id: mumble_userid_t = 0;
                if (api.getLocalUserID.unwrap())(plugin_id, connection, &mut local_id) != OK {
                    return;
                }
                (api.requestUserMove.unwrap())(plugin_id, connection, local_id, *channel_id, std::ptr::null());
            }
            MumbleCommand::SetMuted { muted } => {
                (api.requestLocalUserMute.unwrap())(plugin_id, *muted);
            }
            MumbleCommand::SetDeafened { deafened } => {
                (api.requestLocalUserDeaf.unwrap())(plugin_id, *deafened);
            }
            MumbleCommand::SetUserVolume { session, volume } => {
                (api.setUserLocalVolumeAdjustment.unwrap())(plugin_id, connection, *session, *volume);
            }
            MumbleCommand::SetTransmissionMode { mode } => {
                #[allow(non_upper_case_globals)]
                let tm = match mode {
                    TransmissionMode::Continuous => Mumble_TransmissionMode_MUMBLE_TM_CONTINOUS,
                    TransmissionMode::VoiceActivation => Mumble_TransmissionMode_MUMBLE_TM_VOICE_ACTIVATION,
                    TransmissionMode::PushToTalk => Mumble_TransmissionMode_MUMBLE_TM_PUSH_TO_TALK,
                };
                (api.requestLocalUserTransmissionMode.unwrap())(plugin_id, tm);
            }
            MumbleCommand::SetVadThreshold { value } => {
                // Set both silence and speech thresholds to the same value
                (api.setMumbleSetting_double.unwrap())(
                    plugin_id,
                    Mumble_SettingsKey_MUMBLE_SK_AUDIO_INPUT_VAD_SILENCE_THRESHOLD as mumble_settings_key_t,
                    *value,
                );
                (api.setMumbleSetting_double.unwrap())(
                    plugin_id,
                    Mumble_SettingsKey_MUMBLE_SK_AUDIO_INPUT_VAD_SPEECH_THRESHOLD as mumble_settings_key_t,
                    *value,
                );
            }
            MumbleCommand::SetVoiceHold { value } => {
                (api.setMumbleSetting_int.unwrap())(
                    plugin_id,
                    Mumble_SettingsKey_MUMBLE_SK_AUDIO_INPUT_VOICE_HOLD as mumble_settings_key_t,
                    *value,
                );
            }
        }
    }
}

// ==================== QUERY HELPERS ====================

fn build_server_sync(s: &PluginState, connection: mumble_connection_t) -> MumbleEvent {
    let mut local_session: mumble_userid_t = 0;
    unsafe { (s.api.getLocalUserID.unwrap())(s.id, connection, &mut local_session); }
    let channels = query_all_channels(s, connection);
    let users = query_all_users(s, connection);
    MumbleEvent::ServerSync { local_session, channels, users }
}

fn query_all_channels(s: &PluginState, connection: mumble_connection_t) -> Vec<Channel> {
    unsafe {
        let mut ptr: *mut mumble_channelid_t = std::ptr::null_mut();
        let mut count: usize = 0;
        if (s.api.getAllChannels.unwrap())(s.id, connection, &mut ptr, &mut count) != OK {
            return Vec::new();
        }

        let mut channels = Vec::with_capacity(count);
        for i in 0..count {
            let ch_id = *ptr.add(i);
            if let Some(ch) = build_channel(s, connection, ch_id) {
                channels.push(ch);
            }
        }
        (s.api.freeMemory.unwrap())(s.id, ptr as *const c_void);
        channels
    }
}

fn query_all_users(s: &PluginState, connection: mumble_connection_t) -> Vec<User> {
    unsafe {
        let mut ptr: *mut mumble_userid_t = std::ptr::null_mut();
        let mut count: usize = 0;
        if (s.api.getAllUsers.unwrap())(s.id, connection, &mut ptr, &mut count) != OK {
            return Vec::new();
        }

        let mut users = Vec::with_capacity(count);
        for i in 0..count {
            let uid = *ptr.add(i);
            if let Some(u) = build_user(s, connection, uid) {
                users.push(u);
            }
        }
        (s.api.freeMemory.unwrap())(s.id, ptr as *const c_void);
        users
    }
}

fn build_user(s: &PluginState, connection: mumble_connection_t, user_id: mumble_userid_t) -> Option<User> {
    unsafe {
        let name = get_string(&s.api, s.id, |a, out| {
            (a.getUserName.unwrap())(s.id, connection, user_id, out)
        })?;

        let mut channel_id: mumble_channelid_t = 0;
        if (s.api.getChannelOfUser.unwrap())(s.id, connection, user_id, &mut channel_id) != OK {
            return None;
        }

        let mut mute_state: ffi::mumble_mute_state_t = 0;
        let mut deaf_state: ffi::mumble_deaf_state_t = 0;
        let mut volume_adjustment: f32 = 1.0;
        (s.api.getUserMuteState.unwrap())(s.id, connection, user_id, &mut mute_state);
        (s.api.getUserDeafState.unwrap())(s.id, connection, user_id, &mut deaf_state);
        (s.api.getUserLocalVolumeAdjustment.unwrap())(s.id, connection, user_id, &mut volume_adjustment);

        Some(User {
            session: user_id,
            name,
            channel_id,
            mute_state: mute_state as u32,
            deaf_state: deaf_state as u32,
            volume_adjustment,
        })
    }
}

fn query_setting_double(s: &PluginState, key: mumble_settings_key_t) -> Option<f64> {
    unsafe {
        let mut value: f64 = 0.0;
        if (s.api.getMumbleSetting_double.unwrap())(s.id, key, &mut value) != OK {
            return None;
        }
        Some(value)
    }
}

fn query_setting_int(s: &PluginState, key: mumble_settings_key_t) -> Option<i64> {
    unsafe {
        let mut value: i64 = 0;
        if (s.api.getMumbleSetting_int.unwrap())(s.id, key, &mut value) != OK {
            return None;
        }
        Some(value)
    }
}

fn query_transmission_mode(s: &PluginState) -> Option<TransmissionMode> {
    unsafe {
        let mut tm: mumble_transmission_mode_t = 0;
        if (s.api.getLocalUserTransmissionMode.unwrap())(s.id, &mut tm) != OK {
            return None;
        }
        #[allow(non_upper_case_globals)]
        let mode = match tm {
            Mumble_TransmissionMode_MUMBLE_TM_CONTINOUS => TransmissionMode::Continuous,
            Mumble_TransmissionMode_MUMBLE_TM_PUSH_TO_TALK => TransmissionMode::PushToTalk,
            _ => TransmissionMode::VoiceActivation,
        };
        Some(mode)
    }
}

fn build_channel(s: &PluginState, connection: mumble_connection_t, channel_id: mumble_channelid_t) -> Option<Channel> {
    unsafe {
        let name = get_string(&s.api, s.id, |a, out| {
            (a.getChannelName.unwrap())(s.id, connection, channel_id, out)
        })?;

        // TODO: parent channel ID — API doesn't expose this directly.
        // For now, use 0 as placeholder.
        Some(Channel { id: channel_id, name, parent: 0 })
    }
}

// ==================== FFI HELPERS ====================

unsafe fn get_string(
    api: &MumbleAPI_v_1_3_x,
    plugin_id: mumble_plugin_id_t,
    f: impl FnOnce(&MumbleAPI_v_1_3_x, &mut *const i8) -> mumble_error_t,
) -> Option<String> {
    let mut ptr: *const i8 = std::ptr::null();
    if f(api, &mut ptr) != OK {
        return None;
    }
    let s = CStr::from_ptr(ptr).to_string_lossy().into_owned();
    (api.freeMemory.unwrap())(plugin_id, ptr as *const c_void);
    Some(s)
}
